from __future__ import annotations

import base64
import hashlib
import subprocess
import sys
import tempfile
import zlib
from pathlib import Path

PATCH_SHA256 = "5e833ebdf165f84e8b2edc4f894cdd0fd61ea8137a511d23dc4784763f04cfd4"
PATCH_ZLIB_BASE64 = ""


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Kullanım: apply_v5_alarm_regression_fix.py <kaynak-kökü>")
    root = Path(sys.argv[1]).resolve()
    if not (root / "pubspec.yaml").is_file():
        raise SystemExit(f"Flutter kaynak kökü bulunamadı: {root}")

    patch = zlib.decompress(base64.b64decode(PATCH_ZLIB_BASE64))
    actual = hashlib.sha256(patch).hexdigest()
    if actual != PATCH_SHA256:
        raise SystemExit(f"Patch SHA uyuşmuyor: {actual} != {PATCH_SHA256}")

    subprocess.run(["git", "init", "-q"], cwd=root, check=True)
    with tempfile.NamedTemporaryFile(suffix=".patch", delete=False) as handle:
        handle.write(patch)
        patch_path = Path(handle.name)
    try:
        subprocess.run(
            ["git", "apply", "--whitespace=nowarn", str(patch_path)],
            cwd=root,
            check=True,
        )
    finally:
        patch_path.unlink(missing_ok=True)

    required = {
        "lib/services/notification_service.dart": [
            "requestFullScreenIntentPermission",
            "fullScreenIntent: alarmStyle",
            "AudioAttributesUsage.alarm",
        ],
        "lib/services/reminder_engine.dart": [
            "state.paymentNotificationSlots",
            "Tekrarlı alarm:",
        ],
        "lib/models/mizan_models.dart": [
            "class IncomeEntry",
            "manualOverdueDays",
            "notificationPresentationMode",
            "alarmRepeatMode",
        ],
        "lib/screens/settings_screen.dart": [
            "En az 1, en fazla 10 saat",
            "Alarm tekrar aralığı",
        ],
        "tools/configure_android.py": [
            "USE_FULL_SCREEN_INTENT",
            "VIBRATE",
        ],
    }
    for relative, needles in required.items():
        text = (root / relative).read_text(encoding="utf-8")
        for needle in needles:
            if needle not in text:
                raise SystemExit(f"Zorunlu koruma eksik: {relative}: {needle}")

    print(f"V5 alarm regresyon düzeltmesi uygulandı: SHA-256 {actual}")


if __name__ == "__main__":
    main()
